#include <iostream>

int maxOf(const int& x, const int& y)
{
    if (x >= y)
        return x;
    return y;
}

int main()
{
    int a {};
    int b {};
    std::cin >> a >> b;
    int result { maxOf(a, b) };
    std::cout << "Max: " << result << '\n';
    return 0;
}
